import secrets

class TOTPManager:
    def __init__(self):
        self.totp_cache = {}
        self.validation_window = 3  # Allow 3 time windows (30 seconds each)
        
    def generate_secret(self):
        """Generate a secure TOTP secret"""
        return secrets.token_urlsafe(32)
    
    def create_qr_code(self, secret, user_email, issuer_name="MFA System"):
        """Create QR code for authenticator app setup"""
        totp_uri = pyotp.totp.TOTP(secret).provisioning_uri(
            user_email, issuer_name=issuer_name
        )
        qr = qrcode.QRCode(version=1, box_size=10, border=4)
        qr.add_data(totp_uri)
        qr.make(fit=True)
        img = qr.make_image(fill_color="black", back_color="white")
        
        # Convert to base64 for web display
        buffer = BytesIO()
        img.save(buffer, format='PNG')
        buffer.seek(0)
        return base64.b64encode(buffer.getvalue()).decode()
    
    def generate_totp_code(self, secret):
        """Generate current TOTP code"""
        totp = pyotp.TOTP(secret)
        return totp.now()
    
    def validate_totp_code(self, secret, provided_code):
        """Validate TOTP code with time window protection"""
        try:
            totp = pyotp.TOTP(secret)
            
            # Check current time window
            if totp.verify(provided_code, valid_window=0):
                return True
                
            # Check previous and next time windows for validation
            for i in range(1, self.validation_window):
                if totp.verify(provided_code, valid_window=i):
                    return True
                    
            return False
        except Exception:
            return False
    
    def validate_totp_code_strong(self, secret, provided_code):
        """Strong validation with additional security checks"""
        # Basic format check
        if not provided_code or len(provided_code) != 6:
            return False
            
        # Check if code contains only digits
        if not provided_code.isdigit():
            return False
            
        # Check if code is within reasonable range (000000-999999)
        try:
            code_int = int(provided_code)
            if code_int < 0 or code_int > 999999:
                return False
        except ValueError:
            return False
            
        # Perform actual TOTP validation
        return self.validate_totp_code(secret, provided_code)
    
    def get_totp_info(self, secret):
        """Get TOTP information for debugging"""
        totp = pyotp.TOTP(secret)
        return {
            'current_code': totp.now(),
            'interval': totp.interval,
            'issuer': 'MFA System'
        }

